1	// test-timing reads go test -json output from stdin and writes a Markdown
2	// table of the top N slowest tests to stdout.
3	//
4	// Usage:
5	//
6	//	go test -json ./... | go run ./tools/test-timing
7	//	go run ./tools/test-timing -n 30 < test-output.json
8	package main
9	
10	import (
11		"bufio"
12		"encoding/json"
13		"flag"
14		"fmt"
15		"os"
16		"sort"
17	)
18	
19	type testEvent struct {
20		Action  string  `json:"Action"`
21		Package string  `json:"Package"`
22		Test    string  `json:"Test"`
23		Elapsed float64 `json:"Elapsed"`
24	}
25	
26	func main() {
27		n := flag.Int("n", 20, "number of slowest tests to show")
28		flag.Parse()
29	
30		var results []testEvent
31		scanner := bufio.NewScanner(os.Stdin)
32		for scanner.Scan() {
33			var ev testEvent
34			if err := json.Unmarshal(scanner.Bytes(), &ev); err != nil {
35				continue
36			}
37			if ev.Test == "" {
38				continue
39			}
40			if ev.Action != "pass" && ev.Action != "fail" {
41				continue
42			}
43			results = append(results, ev)
44		}
45		if err := scanner.Err(); err != nil {
46			fmt.Fprintf(os.Stderr, "read error: %v\n", err)
47			os.Exit(1)
48		}
49	
50		sort.Slice(results, func(i, j int) bool {
51			return results[i].Elapsed > results[j].Elapsed
52		})
53	
54		top := results
55		if len(top) > *n {
56			top = top[:*n]
57		}
58	
59		if len(top) == 0 {
60			fmt.Println("# Test Timing Summary\n\nNo test results found.")
61			return
62		}
63	
64		fmt.Printf("# Top %d Slowest Tests\n\n", len(top))
65		fmt.Printf("| Rank | Test | Package | Elapsed (s) | Result |\n")
66		fmt.Printf("|------|------|---------|-------------|--------|\n")
67		for i, ev := range top {
68			status := "PASS"
69			if ev.Action == "fail" {
70				status = "FAIL"
71			}
72			fmt.Printf("| %d | `%s` | `%s` | %.3f | %s |\n", i+1, ev.Test, ev.Package, ev.Elapsed, status)
73		}
74	}
